INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (2, "2025/01/31 12:00:00", 0.0, "2030/01/01 14:59:59", "カリン", 190801, 62, 3.414, "ミッションをクリアすると、\n報酬がもらえますよ！\n頑張ってください", 1, 1, 1, -416.5, 1000001);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (2, "2025/01/31 12:00:00", 0.0, "2030/01/01 14:59:59", "カリン", 190801, 62, 3.099, "ミッションをクリアして、\n報酬をゲットしましょう！", 2, 1, 1, -416.5, 1000002);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (2, "2025/01/31 12:00:00", 0.0, "2030/01/01 14:59:59", "カリン", 190801, 63, 2.801, "受け取ることができる\n報酬があるようです\n確認してみてください", 3, 1, 1, -416.5, 1000003);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (2, "2025/01/31 12:00:00", 0.0, "2030/01/01 14:59:59", "カリン", 190801, 63, 0.0, "報酬がもらえますよ！\nチェックしてみてください", 4, 1, 2, -416.5, 1000004);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1, "2025/01/31 12:00:00", 0.0, "2030/01/01 14:59:59", "カリン", 190801, 64, 2.12, "ギルド管理協会です！\nイベント報酬券をお持ちでしたら、様々なアイテムと交換できますよ", 5, 1, 2, -363.0, 1000005);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (2, "2025/01/31 12:00:00", 0.0, "2030/01/01 14:59:59", "カリン", 190801, 64, 1.68, "お疲れさまです！\nこちらでイベント報酬券とアイテムを交換することができますよ", 6, 1, 1, -363.0, 1000006);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1, "2025/01/31 12:00:00", 0.0, "2030/01/01 14:59:59", "カリン", 190801, 64, 2.33, "いつもありがとうございます！\n報酬交換ですか？\nでは、イベント報酬券とお引き換えいたしますね", 7, 1, 2, -363.0, 1000007);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (7, "2025/01/31 12:00:00", -6.0, "2030/01/01 14:59:59", "ラビリスタ", 133701, 61, 5.18, "今度の敵は、アタシにとっても\n放ってはおけない存在だ\n少年、アタシも全力で行くからさ\n一緒に守ろう、この世界を", 101, 10201, 3, -285.0, 1020101);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (2, "2025/01/31 12:00:00", -2.0, "2030/01/01 14:59:59", "クリスティーナ", 133901, 61, 8.77, "退屈の吹き飛ぶような\n戦いの気配がするなぁ坊や\nさっさとワタシをそこへ連れてゆけ\n世界も守ってやるさ、ついでにな", 201, 10201, 1, -285.0, 1020102);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1, "2025/01/31 12:00:00", 0.0, "2030/01/01 14:59:59", "ネネカ", 133801, 61, 15.5, "おや、私の力が必要……と？\nグレゴールが手伝うそうですよ\n私は戦わないのか、という顔ですね\n……考えておきます", 301, 10201, 6, -285.0, 1020103);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (5, "2025/02/28 12:00:00", 0.0, "2030/01/01 14:59:59", "ランファ", 134301, 61, 9.061, "わたしだけの歌…\n一緒に、探してくれる…？\nあなたがいれば…\nもっとがんばれるから…", 101, 10202, 2, -285.0, 1020201);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (2, "2025/02/28 12:00:00", 0.0, "2030/01/01 14:59:59", "チカ", 134401, 61, 7.699, "同じ唱喚士として、仲間として\n私にできることをします\n…これも、あなたが\n背中を押してくれたおかげですよ", 201, 10202, 1, -285.0, 1020202);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (2, "2025/03/31 12:00:00", 0.0, "2030/01/01 14:59:59", "アオイ", 134601, 61, 8.595, "世界の平和が私とクローチェさんに\nかかってるんですよね？\nぼっちには過大すぎる期待ですけど\nふ、二人でなら背負ってみせます！", 101, 10203, 1, -285.0, 1020301);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (2, "2025/03/31 12:00:00", 0.0, "2030/01/01 14:59:59", "クローチェ", 134501, 61, 7.758, "新しく手に入れたこの翼で…\nナイトさんがどこにいたって\nわたし、駆けつけちゃいますよっ！\nクローチェ・エアリアル発進ですっ", 201, 10203, 1, -285.0, 1020302);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (6, "2025/04/30 12:00:00", 0.0, "2030/01/01 14:59:59", "ルイズマリー", 132302, 61, 7.0, "今日はダーリンとの初デート♪\n二人でショッピングして、その後は\n…って私、指名手配されてる！？\nちょ、た…助けてダーリン～！！", 101, 10204, 2, -285.0, 1020401);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (2, "2025/04/30 12:00:00", 0.0, "2030/01/01 14:59:59", "イロハ", 132402, 61, 7.904, "ルイちゃんのおばあちゃん優しくて\nいつもにこにこで、イロハ大好き♪\nでも一番好きなのは、角がすっごく\n大きくてかっこいいとこなんだ～♪", 201, 10204, 1, -285.0, 1020402);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (2, "2025/04/30 12:00:00", 0.0, "2030/01/01 14:59:59", "ソノ", 132502, 61, 8.487, "ノゾミちゃんのおかげで売上が安定\nしてきたのに、臨時休業、痛すぎる\n…ま、ルイちゃんのために\n一肌脱ぐか。行くよイロハ～", 301, 10204, 4, -285.0, 1020403);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (2, "2025/05/31 12:00:00", 0.0, "2030/01/01 14:59:59", "カノン", 134901, 61, 8.763, "ヲ～ッホッホ♪\nあたくし様と同じお空気を吸える\nお幸運を噛みしめなさいですわ～♪\nヲ～ッホッホッホ～♪", 101, 10205, 1, -285.0, 1020502);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (3, "2025/05/31 12:00:00", 0.0, "2030/01/01 14:59:59", "ツムギ", 134801, 61, 6.417, "いきますよ騎士さん！\nカノンさんと力を合わせて…力を…\n…本当にあの人なんなんです？\nこれまでになく不安なんですけど！", 201, 10205, 1, -285.0, 1020503);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (7, "2025/06/30 12:00:00", 0.0, "2030/01/01 14:59:59", "エリス", 135001, 61, 10.335, "『願いが叶う海岸』か…怪しい\nだというのに、阿賀斗紫布菜たちは\n呑気に戯れている…見ていられない\n騎士クンは、わたしが守ってみせる", 101, 10206, 3, -285.0, 1020601);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (4, "2025/06/30 12:00:00", 0.0, "2030/01/01 14:59:59", "シェフィ", 135101, 61, 6.281, "せっかくの夏休みなんだし\nたまにはビーチでゆっくりしましょ\n…え、もしかしてこの夏もあんまり\n休めなかったりする感じなの？", 201, 10206, 2, -285.0, 1020602);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (2, "2025/06/30 12:00:00", 0.0, "2030/01/01 14:59:59", "プレシア", 135201, 61, 12.244, "いっぱい。たべて\nおおきく。なると\nせーぎ。まもれる。はず\nお兄。いっしょに。スイカ。たべよ", 301, 10206, 1, -285.0, 1020603);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (8, "2025/07/31 12:00:00", 0.0, "2030/01/01 14:59:59", "クリア", 135301, 61, 6.339, "ひと夏の冒険のはじまりです！\nアネモネさんも楽しんでくれたら\n…できれば、もう少し\n仲良くなれたらうれしいな…", 101, 10207, 2, -285.0, 1020701);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (9, "2025/07/31 12:00:00", 0.0, "2030/01/01 14:59:59", "アネモネ", 135401, 61, 8.184, "─幻の花…\n本当にあるのか謎─ですけど\n探すくらいは、\n付き合ってもいいです", 201, 10207, 7, -285.0, 1020702);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (2, "2025/08/31 12:00:00", 0.0, "2030/01/01 14:59:59", "アイラ", 129101, 61, 3.906, "あははっ！　笑う門には福来る！\n笑ってればきっと、複製世界にも\n未来はやってくるって信じてる！\nそうだよね、シナツちゃん！", 101, 10208, 9, -285.0, 1020801);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (2, "2025/08/31 12:00:00", 0.0, "2030/01/01 14:59:59", "シナツ", 129201, 61, 14.465, "繰り返されるリセットの先の未来\n何度願っても手に入らなかった未来\n…でも、私は諦めない。絶対にだ\nキミも同じだろ…アイラ？", 201, 10208, 1, -285.0, 1020802);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (3, "2025/08/31 12:00:00", 0.0, "2030/01/01 14:59:59", "ヒヨリ", 100101, 61, 8.662, "アイラの世界のみんなも、\n一生懸命生きてるんだ…！\n…なのに、世界の危機だなんて！\nあたし、絶対、絶対力になるよ！", 301, 10208, 4, -285.0, 1020803);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (3, "2025/08/31 12:00:00", 0.0, "2030/01/01 14:59:59", "レイ", 100301, 61, 10.915, "シナツ…もう一人の私\n彼女が大切にしている世界を\n絶対に終わらせはしない…！\n彼女と笑い合える未来のために！", 401, 10208, 1, -285.0, 1020804);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (7, "2025/09/30 12:00:00", 0.0, "2030/01/01 14:59:59", "ユキノ", 135802, 61, 6.042, "あ、ど、ども…\nあ、あんま見ねぇでくれっと\nその、恥ずかしくて…\n体が熱くなって、溶けちまう…", 101, 10209, 1, -285.0, 1020901);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1, "2025/09/30 12:00:00", 0.0, "2030/01/01 14:59:59", "サツキ", 135903, 61, 9.402, "なんで俺が幽霊に…意味不明だ\nこれじゃ死んでも死にきれねェ\n悪ィがこれも何かの縁だ、\nよろしく頼むぜ騎士公", 201, 10209, 4, -285.0, 1020902);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1, "2025/09/30 12:00:00", 0.0, "2030/01/01 14:59:59", "ルルィ", 136902, 61, 8.16, "う、うじゅる…\nサツキ姉しゃまを助けるためにも\nまずは、腹ごしらえでしゅね…！\nタコ焼き、召し上がってくだしゃい", 301, 10209, 8, -285.0, 1020903);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (2, "2025/10/31 12:00:00", 0.0, "2030/01/01 14:59:59", "カスミ", 137401, 61, 5.0, "ひさしぶりのジオ・ゲヘナ\n歓迎パーティーで起きた殺人事件！\nランドソルの名探偵の名にかけて\n解き明かしてみせようじゃないか！", 101, 10210, 3, -285.0, 1021001);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1, "2025/10/31 12:00:00", 0.0, "2030/01/01 14:59:59", "アラクネ", 136001, 61, 8.12, "…わたしはどこの誰なのでしょう\nどこから来てどこへ行くのでしょう\nこの事件の真相が分かれば、\n何かが掴めるような気がいたします", 201, 10210, 4, -285.0, 1021002);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (2, "2025/10/31 12:00:00", 0.0, "2030/01/01 14:59:59", "ナーナ", 136202, 61, 6.386, "ナーナ、すいりとかろんぱとか、\nむずかしくてわかんないけど…\nお友だちとドーナツのためならっ\nせーいっぱいがんばるよっ！", 301, 10210, 4, -285.0, 1021003);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (4, "2025/11/30 12:00:00", 0.0, "2030/01/01 14:59:59", "ユイ", 136402, 61, 7.438, "騎士クンに想いを伝えたい…だから\nミソラちゃん、わたしがんばるね！\n…あれ？　わたし、なんでこんなに\n必死になってるんだろう…？", 101, 10211, 3, -285.0, 1021101);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (5, "2025/11/30 12:00:00", 0.0, "2030/01/01 14:59:59", "ミソラ", 136302, 61, 8.35, "騎士さんとのデートはわたしに\nお任せです★　なのでユイさんは\n安心して計画に専念して…たくさん\nドキドキしちゃってくださいね", 201, 10211, 1, -285.0, 1021102);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (2, "2025/12/31 12:00:00", 0.0, "2030/01/01 14:59:59", "シズル", 136501, 61, 5.0, "新しい年がやってくるね！\nお正月の料理も飾りつけも、\nお姉ちゃんにお任せだよ♪\nみんなで楽しく新年を迎えよう！", 101, 10212, 1, -285.0, 1021201);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (2, "2025/12/31 12:00:00", 0.0, "2030/01/01 14:59:59", "リノ", 137902, 61, 5.25, "おうちの掃除もトラブルも、 \n世界を揺るがす大ピンチも！\n今年のことは今年のうちに \nサッサと片付けちゃいますっ！", 201, 10212, 1, -285.0, 1021202);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (2, "2025/12/31 12:00:00", 0.0, "2030/01/01 14:59:59", "ラビリスタ", 106801, 61, 7.5, "年の瀬はギルドマスターも\nつい駆け回っちゃう忙しい時期だ！\n一年いろいろあったけど\nお互いイイ年を迎えよう、少年！", 301, 10212, 1, -285.0, 1021203);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (2, "2026/01/31 12:00:00", 0.0, "2030/01/01 14:59:59", "ライラエル", 126501, 61, 8.204, "漂う異国の料理の香り…それだけで\n世界中を旅した気分に浸れますね\nふふ、ほらクローチェ\nあまりはしゃぎすぎないように…♪", 101, 10213, 1, -285.0, 1021301);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (2, "2026/01/31 12:00:00", 0.0, "2030/01/01 14:59:59", "ネフィ＝ネラ", 129701, 61, 7.176, "異界の姫君と煮炊きにて競い合う…\n感奮興起、いとをかし\n華やかなる祭典と相成るよう、一肌\n脱がせていただきとう存じまする", 201, 10213, 1, -285.0, 1021302);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (5, "2026/01/31 12:00:00", 0.0, "2030/01/01 14:59:59", "ヴァイオレット", 133101, 61, 8.602, "『ビストロプリンセス』のために\n料理の特訓を重ねてまいりました\nこの料理で騎士様の…い、いえ\n皆様の心とお腹を満たしますわ！", 301, 10213, 1, -285.0, 1021303);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (3, "2026/02/06 12:00:00", 0.0, "2030/01/01 14:59:59", "ライラエル", 138101, 61, 10.14, "多様な味わいが織りなすハーモニー\nそれこそが我が国の矜持です\nもしもそれを乱すようであれば\nわたしも優しくはありませんよ？", 102, 10213, 1, -285.0, 1021304);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (7, "2026/02/06 12:00:00", 0.0, "2030/01/01 14:59:59", "ネフィ＝ネラ", 138201, 61, 10.152, "煉獄の穢土にてひと際輝く民草の心\n此れを守護りまするがわっちの責務\n如何な困難待ち受けようと\n不退転の矜持に揺らぎはありんせん", 202, 10213, 1, -285.0, 1021305);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (3, "2026/02/06 12:00:00", 0.0, "2030/01/01 14:59:59", "ヴァイオレット", 138001, 61, 9.688, "裏世界の皆様は危機を脱し、\n残るはランドソルの皆様のみ…\n彼らを救い出すために、どうか…\nお立ち下さいペコリーヌ姫…！", 302, 10213, 4, -285.0, 1021306);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1, "2026/02/12 12:00:00", 0.0, "2030/01/01 14:59:59", "ペコリーヌ", 138301, 61, 5.928, "みなさん、お待たせしちゃいました\nペコリーヌ、完全復活です☆\nみなさんの食卓を守るため\nもう二度と、わたしはめげません！", 401, 10213, 2, -285.0, 1021307);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (2, "2026/02/28 12:00:00", 0.0, "2030/01/01 14:59:59", "ワカナ", 138702, 61, 9.19, "成行きで参加することになっちゃっ\nた尻相撲大会。ううっ、恥ずかしい\nけどやるしかないよね。…騎士さん\nいっぱい応援してくださいね？", 101, 10214, 4, -285.0, 1021401);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (3, "2026/02/28 12:00:00", 0.0, "2030/01/01 14:59:59", "シオリ", 138802, 61, 8.724, "「お姉ちゃんを守れる自分になる」\nあの日の約束、今こそ果たしてみせ\nます。例えお姉ちゃんに背くことに\nなっても。例えそれが尻相撲でも！", 201, 10214, 1, -285.0, 1021402);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1, "2026/03/31 12:00:00", 0.0, "2030/01/01 14:59:59", "グレイス", 138902, 61, 7.758, "私がへんたいふしんしゃさんって…\nただ生きているだけなのに、ひどい\n…まぁ死んでるんですけど…とか\n言ってる暇もない感じですか？", 101, 10215, 4, -285.0, 1021501);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (4, "2026/03/31 12:00:00", 0.0, "2030/01/01 14:59:59", "キョウカ", 139002, 61, 6.375, "あの、助けてください！\n私がへんたいふしんしゃさんに\nなっちゃったみたいなんです…！\nどういう意味かは私もわかりません", 201, 10215, 6, -285.0, 1021502);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1, "2026/03/31 12:00:00", 0.0, "2030/01/01 14:59:59", "ルルィ", 136902, 61, 6.173, "ましゃか、グレイス姉しゃまたちが\nへんたいふしんしゃさんだなんて…\n騎士しゃん。あたちたちも協力ちて\n二人の破滅エンドを回避ちましょう", 301, 10215, 6, -285.0, 1021503);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (2, "2026/04/30 12:00:00", 0.0, "2030/01/01 14:59:59", "ミホ", 139202, 61, 4.202, "違う世界に来ちゃうし、\n驚きの連続だけど…\nわたしも精いっぱい頑張ります！\nアストルムのみんなと一緒に！", 101, 10216, 6, -285.0, 1021601);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1, "2026/04/30 12:00:00", 0.0, "2030/01/01 14:59:59", "マホ", 139302, 61, 2.842, "想定外の事象が発生したな…だが\nいかなる苦境も切り抜けてみせる\nいつもの自分とは違う姿になっても\nわたしはわたし、西住流だ", 201, 10216, 6, -285.0, 1021602);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1, "2026/04/30 12:00:00", 0.0, "2030/01/01 14:59:59", "エリカ", 139402, 61, 4.598, "何でこんなことになっているのか\n全然わからないけど、迷ってる暇は\nないわ。黒森峰の次期隊長として、\n前進あるのみ！　これも戦車道よ！", 301, 10216, 4, -285.0, 1021603);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (3, "2026/05/31 12:00:00", 0.0, "2030/01/01 14:59:59", "リリ", 125802, 61, 6.533, "わたくしたちの悲願は、ロストさせ\nてしまった方々をお助けすること…\nそのためなら、どのような辛苦にも\n耐え抜いてみせます…！", 101, 10217, 4, -285.0, 1021701);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (3, "2026/05/31 12:00:00", 0.0, "2030/01/01 14:59:59", "プレシア", 126102, 61, 5.0, "みんなも。せーぎも。\nクリアも。パパ、も。\nぜったい、たすける。\nみててね。お兄。", 301, 10217, 3, -285.0, 1021702);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (4, "2026/05/31 12:00:00", 0.0, "2030/01/01 14:59:59", "クリア", 126002, 61, 5.214, "癒しの力を使うこと…\nもう、ためらいません！\nモネちゃんやお兄さん…\nみんなに許してもらうためにも！", 201, 10217, 3, -285.0, 1021703);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (3, "2026/05/31 12:00:00", 0.0, "2030/01/01 14:59:59", "リリ", 139501, 61, 8.781, "ヴァルキュリア─皆様を助けたい\nという願いを、力にできるのなら…\nわたくしたちは、きっと誰にも\n負けません！　一意専心です…！", 102, 10217, 1, -285.0, 1021704);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1, "2026/05/31 12:00:00", 0.0, "2030/01/01 14:59:59", "クリア", 139601, 61, 6.529, "このヴァルキュリアって職業、\nまるで天使みたいな格好ですよね\nうーん…『聖女』ちゃんって\n呼ばれるよりは、マシかな？", 202, 10217, 2, -285.0, 1021705);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (2, "2026/05/31 12:00:00", 0.0, "2030/01/01 14:59:59", "プレシア", 139701, 61, 3.195, "ばるきり。もーど。\nはね。まっしろ。\nはっぴーちゃんと。おなじ。\nいいかんじ。", 302, 10217, 3, -285.0, 1021706);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (2, "2026/04/10 12:00:00", 0.0, "2030/01/01 14:59:59", "カリン", 190801, 62, 3.414, "ミッションをクリアすると、\n報酬がもらえますよ！\n頑張ってください", 1, 2, 1, -416.5, 2000001);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (2, "2026/04/10 12:00:00", 0.0, "2030/01/01 14:59:59", "カリン", 190801, 62, 3.099, "ミッションをクリアして、\n報酬をゲットしましょう！", 2, 2, 1, -416.5, 2000002);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (2, "2026/04/10 12:00:00", 0.0, "2030/01/01 14:59:59", "カリン", 190801, 63, 2.801, "受け取ることができる\n報酬があるようです\n確認してみてください", 3, 2, 1, -416.5, 2000003);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (2, "2026/04/10 12:00:00", 0.0, "2030/01/01 14:59:59", "カリン", 190801, 63, 0.0, "報酬がもらえますよ！\nチェックしてみてください", 4, 2, 2, -416.5, 2000004);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1, "2026/04/10 12:00:00", 0.0, "2030/01/01 14:59:59", "カリン", 190801, 64, 2.12, "ギルド管理協会です！\nイベント報酬券をお持ちでしたら、様々なアイテムと交換できますよ", 5, 2, 2, -363.0, 2000005);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (2, "2026/04/10 12:00:00", 0.0, "2030/01/01 14:59:59", "カリン", 190801, 64, 1.68, "お疲れさまです！\nこちらでイベント報酬券とアイテムを交換することができますよ", 6, 2, 1, -363.0, 2000006);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1, "2026/04/10 12:00:00", 0.0, "2030/01/01 14:59:59", "カリン", 190801, 64, 2.33, "いつもありがとうございます！\n報酬交換ですか？\nでは、イベント報酬券とお引き換えいたしますね", 7, 2, 2, -363.0, 2000007);
